isDisabled:
{{
  InputBazowa.text === undefined ||
  InputBazowa.text === null ||
  InputBazowa.text === "" ||
  isNaN(Number(InputBazowa.text))
}}

onClick:
{{
  Number(SliderJST.value) === 0
    ? updateBazowaG.run().then(() => {
        showAlert("Zmieniono wartość bazową", "success");
        getBazowaG.run();
        closeModal(ModalZmienBazowa.name);
      })
    : updateBazowaP.run().then(() => {
        showAlert("Zmieniono wartość bazową", "success");
        getBazowaP.run();
        closeModal(ModalZmienBazowa.name);
      })
}}
